import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest'
import { getHealthResponse } from './health.js'

describe('getHealthResponse', () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('returns status "ok"', () => {
    const result = getHealthResponse()
    expect(result.status).toBe('ok')
  })

  it('returns a valid ISO 8601 timestamp', () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const result = getHealthResponse()
    expect(result.timestamp).toBe('2026-04-05T12:00:00.000Z')
    // Verify it's a valid date
    expect(new Date(result.timestamp).toISOString()).toBe(result.timestamp)
  })

  it('returns uptime_seconds as an integer', () => {
    const result = getHealthResponse()
    expect(typeof result.uptime_seconds).toBe('number')
    expect(Number.isInteger(result.uptime_seconds)).toBe(true)
  })

  it('returns increasing uptime_seconds over time', () => {
    vi.setSystemTime(new Date('2026-04-05T12:00:00.000Z'))
    const first = getHealthResponse()
    vi.advanceTimersByTime(5000)
    const second = getHealthResponse()
    expect(second.uptime_seconds).toBeGreaterThan(first.uptime_seconds)
    expect(second.uptime_seconds - first.uptime_seconds).toBe(5)
  })
})

